#!/usr/bin/env python
"""
MABE Bootstrap: Pareto Multi-Objective Optimization
====================================================
Adds core/pareto.py — NSGA-II style non-dominated sorting + crowding distance
Patches core/de_novo_generator.py — ranking_mode="pareto" in generate_candidates()
  and generate_and_screen()
Adds tests/test_pareto.py — 40 tests

Three default objectives (all MAXIMIZED internally):
  1. Affinity:         log_Ka_pred (higher = stronger)
  2. Selectivity:      min_gap (higher = more selective)
  3. Synthesizability: -sa_score_val (lower SA = easier; negated)

Custom objectives supported via Objective() dataclass.
Auto-selects 2-obj (affinity+SA) or 3-obj (affinity+selectivity+SA)
based on whether interferent data is present.

Usage:
  python bootstrap_pareto.py
  python -m pytest tests/test_pareto.py tests/test_de_novo_generator.py -v

Zero regression: all existing 77 de novo + 5 scorer + 19 novel tests pass.
Supersedes: (patches de_novo_generator.py in-place)
"""
import base64, os, sys, shutil

def write_b64(path, data_b64):
    os.makedirs(os.path.dirname(path), exist_ok=True)
    with open(path, "wb") as f:
        f.write(base64.b64decode(data_b64))
    print(f"  Written: {path} ({os.path.getsize(path)} bytes)")

def main():
    root = os.path.dirname(os.path.abspath(__file__))
    if not os.path.isfile(os.path.join(root, "core", "universal_schema.py")):
        root = os.path.dirname(root)
    if not os.path.isfile(os.path.join(root, "core", "universal_schema.py")):
        print("ERROR: Run from MABE repo root.")
        sys.exit(1)

    print("MABE Bootstrap: Pareto Multi-Objective Optimization")
    print("=" * 55)

    dng = os.path.join(root, "core", "de_novo_generator.py")
    bak = dng + ".pre_pareto.bak"
    if not os.path.isfile(bak):
        shutil.copy2(dng, bak)
        print(f"  Backup: {bak}")

    write_b64(os.path.join(root, "core/pareto.py"), "")
    write_b64(os.path.join(root, "tests/test_pareto.py"), "")
    write_b64(os.path.join(root, "core/de_novo_generator.py"), "")

    print()
    print("Validation:")
    print("  python -m pytest tests/test_pareto.py tests/test_de_novo_generator.py -v")
    print()
    print("Expected: 117 passed (40 pareto + 77 de novo), 0 failed")

if __name__ == "__main__":
    main()